import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './composents/entete/header'; // Remplacez 'component' par 'components'

import Footer from './composents/footer/footer';
import HomePage from './pages/home/homePage'; // Assurez-vous du bon nom ici, peut-être que le fichier s'appelle HomePage.js

import QuiJeSuis from './pages/qjs/pageQjs';

import MesCompetences from './pages/cpts/competences'; // Assurez-vous que le chemin est correct
import MesProjets from './pages/projets/projets'; // Assurez-vous que le chemin est correct

const App = () => {
  return (
    <Router>
      <Header />
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/pageQjs" element={<QuiJeSuis />} />

        <Route path="/competences" element={<MesCompetences />} />
        <Route path="/projets" element={<MesProjets />} />
      </Routes>
      <Footer />
    </Router>
  );
};

export default App;
